               {/* Add more to fill space if needed */}
               {partners.map((p, i) => (
                 <div key={`p1-dup-${i}`} className="font-bold text-2xl md:text-3xl flex items-center gap-4 grayscale opacity-60 shrink-0" style={{ color: p.color }}>
